// src/pages/MyGroups.jsx

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import GroupCard from '../components/GroupCard'; // Le composant de carte de groupe

const MyGroups = ({ currentUser }) => {
    const [groups, setGroups] = useState([]); // Liste des groupes
    const [isLoading, setIsLoading] = useState(true); // Chargement des données

    // Données mockées pour simuler une récupération depuis une API
    const mockGroups = [
        {
            id: 1,
            name: "Groupe A",
            members: ["alice", "bob", "charlie"],
            creator: "alice"
        },
        {
            id: 2,
            name: "Groupe B",
            members: ["alice", "david", "eve"],
            creator: "alice"
        }
    ];

    useEffect(() => {
        // Simuler un délai de chargement
        setTimeout(() => {
            const userGroups = mockGroups.filter(group =>
                group.members.includes(currentUser.username) // Vérifier si l'utilisateur est dans les membres
            );
            setGroups(userGroups);
            setIsLoading(false);
        }, 1000);
    }, [currentUser]);

    // Fonction pour créer un nouveau groupe
    const createGroup = () => {
        // Tu peux ouvrir un modal ou rediriger vers une page de création
        // Par exemple, redirige vers une page de création de groupe
        window.location.href = '/create-group';
    };

    return (
        <div className="my-groups-page">
            <h1>Mes Groupes</h1>
            {isLoading ? (
                <p>Chargement des groupes...</p>
            ) : (
                <>
                    <div className="group-list">
                        {groups.length > 0 ? (
                            groups.map(group => (
                                <GroupCard
                                    key={group.id}
                                    id={group.id}
                                    name={group.name}
                                    members={group.members}
                                    creator={group.creator}
                                />
                            ))
                        ) : (
                            <p>Tu n'as rejoint aucun groupe pour l'instant.</p>
                        )}
                    </div>

                    {/* Bouton de création de groupe */}
                    <button className="create-group-btn" onClick={createGroup}>
                        Créer un nouveau groupe
                    </button>
                </>
            )}
        </div>
    );
};

export default MyGroups;
